array_filter(
				Models_Contacts::instance()->get_all(),
				function ( $contact ) {
					if ( ! isset( $contact['display'] ) ) {
						return true;
					}
					$is_visible = Entity_Visibility::instance()->is_show_view( $contact['display'] );
					return $is_visible;
				}
			)

array_map(
		function ( $match ) {
			return array(
				'value'    => $match[1],
				'label'    => $match[3],
				'selected' => ! empty( $match[2] ), // true si la opción está seleccionada
			);
		},
		$matches
	)

array_map(
            function ($data) {
                static $i = 0;
                if (!isset($data[$this->primaryKey])) {
                    if ($this->autoIncrement) {
                        $data[$this->primaryKey] = $i;
                        $i++;
                    } else {
                        throw new \InvalidArgumentException("Primary key '{$this->primaryKey}' is required.");
                    }
                }

                return $data;
            },
            $defaultEntities
        )

